# ================BUILDING (NEW,SURVEYED,RESURVEYED)========================================================== 	
	LAYER
		NAME 'BLD'
		TYPE POINT
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo 
		INCLUDE "datashare.inc"
		DATA 'sp_geometry FROM (select v.* FROM vw_att_details_building_map v inner join user_permission_area  m on v.region_id=m.region_id and v.province_id=m.province_id and m.user_id=%userid%) as a USING UNIQUE system_id USING srid=4326'
		FILTER (%layerFilter% AND (%NetworkFilter%))
		VALIDATION
			'layerFilter'   '.*'		
			'NetworkFilter'   '.*'
		    'userid' '.*'			
		END
		METADATA
			'ows_title' 'Building'
		END
		STATUS OFF
		GROUP 'Network'		
		CLASS
			NAME 'Building' 	
			EXPRESSION ('[building_status]' eq 'New')			
			STYLE
				SYMBOL "icons/building.png" 
				SIZE 18			
			END	  
		END
		CLASS
			NAME 'Building' 	
			EXPRESSION ('[building_status]' = 'Surveyed')			
			STYLE
				SYMBOL "icons/building_yellow.png" 
				SIZE 18			
			END	  
		END
		CLASS
			NAME 'Building' 	
			EXPRESSION ('[building_status]' = 'Resurveyed')			
			STYLE
				SYMBOL "icons/building_red.png" 
				SIZE 18			
			END	  
		END
	END	
