# ===================BUILDING (APPROVED CENTROID POINT)======================================================= 
	LAYER
		NAME 'BLDC'
		TYPE POINT
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo		
		INCLUDE "datashare.inc"
		DATA 'sp_centroid FROM (select v.* FROM vw_att_details_building_MAP v inner join user_permission_area  m on v.region_id=m.region_id and v.province_id=m.province_id and m.user_id=%userid%) as a USING UNIQUE system_id USING srid=4326'
		FILTER (%layerFilter% AND (%NetworkFilter%))
		VALIDATION
			'layerFilter'   '.*'		
			'NetworkFilter'   '.*'
			'userid' '.*'			
		END
		METADATA
			'ows_title' 'Building'
		END
		STATUS OFF
		GROUP 'Network'

		CLASS
			#NAME 'Non RFS Building'
			NAME 'N-RFS Residential High Rise'
			#EXPRESSION ((('[rfs_status]' eq 'Non-RFS') OR ('[rfs_status]' eq 'N-RFS')) && (('[category]' eq 'Residential') && ( [home_pass] >= 10)))
			STYLE
				SYMBOL [image_icon]
				#SIZE 18        
			END
		END
		
			        			       
	END
# ================ BUILDING STRUCTURE========================================================== 	
	LAYER
		NAME 'STR'
		TYPE POINT
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo 
		INCLUDE "datashare.inc"
		DATA 'sp_geometry FROM (select v.* FROM vw_att_details_structure_map v inner join user_permission_area  m on v.region_id=m.region_id and v.province_id=m.province_id and m.user_id=%userid%) as a USING UNIQUE system_id USING srid=4326'
		FILTER (%layerFilter% AND (%NetworkFilter%))
		VALIDATION
			'layerFilter'   '.*'	
			'NetworkFilter'   '.*'
			'userid' '.*'			
		END
		METADATA
			'ows_title' 'Structure'
		END
		STATUS OFF
		GROUP 'Network'		
		CLASS
			NAME 'Structure'
            EXPRESSION ('[network_status]'  eq 'P' && '[geom_type]'  eq 'Point')  			
			STYLE
				SYMBOL [icon_path]
				SIZE 30			
			END
            			
		END
		CLASS
			NAME 'Structure'
            EXPRESSION ('[network_status]'  eq 'A' && '[geom_type]'  eq 'Point')  			
			STYLE
				SYMBOL [icon_path] 
				SIZE 20			
			END
            			
		END
		CLASS
			NAME 'Structure'
            EXPRESSION ('[network_status]'  eq 'D' && '[geom_type]'  eq 'Point')  			
			STYLE
				SYMBOL [icon_path]
				SIZE 30			
			END
            			
		END			
	END	

