	# ================================== CABLE ======================================== 
	LAYER
		NAME 'CBL'
		TYPE LINE
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		#EXTENT 72.504366 18.900959 73.403214 19.320367
		INCLUDE "datashare.inc"	
		DATA 'sp_geometry FROM (select v.* FROM vw_att_details_cable_map v inner join user_permission_area  m on v.region_id=m.region_id and v.province_id=m.province_id and m.user_id=%userid%) as a USING UNIQUE system_id USING srid=4326'
		FILTER (%layerFilter% AND (%NetworkFilter%))
		VALIDATION
			'layerFilter' '.*'
			'NetworkFilter' '.*'		
			'userid' '.*'			
		END
		METADATA
			'ows_title' 'CABLE'
		END
		STATUS OFF
		GROUP 'Network'
		TRANSPARENCY 100
		LABELITEM 'cable_cores'
		PROJECTION
			'proj=longlat'
			'datum=WGS84'
			'no_defs'
		END
		CLASSITEM 'cable_cores' 		 
		#====================Planned======================
		CLASS 
			EXPRESSION ('[network_status]'  eq 'P')					
		     STYLE
				WIDTH 2
				COLOR [color_code]				                					
				PATTERN 10 5  END
			END		
			LABEL 
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				FONT arial
				TYPE truetype
				COLOR 0 0 0				
				SIZE 8
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR [color_code]  # background rect.
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END
		END	
		#====================Dormant======================		
		CLASS 
			EXPRESSION ('[network_status]'  eq 'D')						
		     STYLE
				WIDTH 2
				COLOR [color_code]				                					
				PATTERN 10 5 0 5  END
			END		
			LABEL 
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				FONT arial
				TYPE truetype
				COLOR 0 0 0				
				SIZE 8
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR [color_code]  # background rect.
				END				
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END
		END	
		#====================As-Built======================
		CLASS 
			EXPRESSION ('[network_status]'  eq 'A')						
		     STYLE
				WIDTH 2
				COLOR [color_code]				                						
			END		
			LABEL 
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				FONT arial
				TYPE truetype
				COLOR 0 0 0				
				SIZE 8
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR [color_code]  # background rect.
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END
		END		
	END
