			'proj=longlat'
			'datum=WGS84'
			'no_defs'
		END
		CLASSITEM 'count_ducts' 
		CLASS 
			NAME "count_ducts"
			TEXT "[count_ducts]"
			EXPRESSION "count_ducts"
			STYLE
				WIDTH 3
				COLOR 255 0 0
				LINECAP ROUND
				PATTERN 10 10 END
			END
			LABEL 
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				FONT arial
				TYPE truetype
				COLOR 0 0 0
				#COLOR  255 0 0
				SIZE 8
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR 255 0 0  # background rect.
				END
				STYLE
					GEOMTRANSFORM 'labelunderline'
					COLOR   0 0 255 # underline
					OFFSET 	0 -1 	# with some offset
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END
		END
		CLASS 
			NAME "Out_Of_Range"   
			TEXT "[count_ducts]"
			STYLE
				WIDTH 3
				COLOR 255 0 0
				LINECAP ROUND
				PATTERN 10 10 END
			END
			LABEL 
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				FONT arial
				TYPE truetype
				COLOR 0 0 0
				#COLOR  255 0 0
				SIZE 8
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR 255 0 0  # background rect.
				END
				STYLE
					GEOMTRANSFORM 'labelunderline'
					COLOR  0 0 255  # underline
					OFFSET 0 -1 	# with some offset
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END
		END
	END

