		TYPE POINT
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo 
		INCLUDE "datashare.inc"
		DATA 'sp_geometry FROM (select v.* FROM vw_att_details_vault_map v inner join user_permission_area  m on v.region_id=m.region_id and v.province_id=m.province_id and m.user_id=%userid%) as a USING UNIQUE system_id USING srid=4326'
		FILTER (%layerFilter% AND (%NetworkFilter%))  
