			'layerFilter' '.*'
			'NetworkFilter' '.*'		
			'userid' '.*'			
		END
		METADATA
			'ows_title' 'Vault'
		END
		STATUS OFF
		GROUP 'Network'		
		CLASS
			NAME 'Vault'
            EXPRESSION ('[network_status]'  eq 'P')  			
			STYLE
